let data = msg.payload.toString().split(",");

let t = parseFloat(data[1]);
let h = parseFloat(data[2]);

let alertMsg = "";
const tmax = 30;
const hmax = 50;

// เช็คเงื่อนไขเหมือนเดิม
if (t > tmax && h > hmax) {
    alertMsg = "🔥 อุณหภูมิสูงเกินไป: " + t + "°C\n💧 ความชื้นสูงเกินไป: " + h + "%";
} else if (t > tmax) {
    alertMsg = "🔥 อุณหภูมิสูงเกินไป: " + t + "°C";
} else if (h > hmax) {
    alertMsg = "💧 ความชื้นสูงเกินไป: " + h + "%";
}

if (alertMsg !== "") {
    msg.payload = {
        chatId: 8786949881, // ตรวจสอบ ID นี้อีกครั้งว่าถูกไหม
        type: 'message',
        content: "⚠️ แจ้งเตือนสถานะ!\n" + alertMsg
    };
    return msg;
}

return null;
